function getNameById(id, callback) {
  // simulating async request
  const randomRequestTime = Math.floor(Math.random() * 100) + 200;

  setTimeout(() => {
    callback("User" + id);
  }, randomRequestTime);
}

function mapLimit(inputs, limit, iterateeFn, callback) {
  const allResults = new Array(inputs.length);
  let pendingTasks = inputs.length;
  const waiting = [];
  let concurrentTasks = 0;

  inputs.forEach((input, index) => {
    const funcToExec = (input, index) => {
      iterateeFn(input, (val) => {
        //a task completed
        allResults[index] = val;
        pendingTasks--;
        concurrentTasks--;


        //all tasks completed
        if (pendingTasks === 0) {

          callback(allResults);
        }

        //check if waiting queue has tasks and concurrent tasks has not reached limit
        if (concurrentTasks < limit && waiting.length) {
          const waitingTask = waiting.shift();
          waitingTask();
        }
      });
    };

    //if concurrent limit reached then store task in queue
    if (concurrentTasks >= limit) {
      waiting.push(() => funcToExec(input, index));
    } else {
      // execute task
      concurrentTasks++;
      funcToExec(input, index);
    }
  });
}

