function mapLimit(inputs, limit, iterateeFn, callback) {
  // implement here
  const inputsArray = inputs.map((index, item) => {
    return { index: index - 1, value: item };
  });
  const output = [];
  let completeCount = 0;
  let i = 0;
  for (i = 0; i < limit; i++) {
    process(inputsArray[i]);
  }

  function process(item) {
    iterateeFn(item.value, (result) => {
      output[item.index] = result;
      completeCount++;

      if (i < inputs.length) {
        process(inputsArray[i++]);
      } else if (completeCount === inputs.length) {
        callback(output);
      }
    });
  }
}
