function getNameById(id, callback) {
    // simulating async request
    const randomRequestTime = Math.floor(Math.random() * 100) + 200;

    setTimeout(() => {
        callback("User" + id)
    }, randomRequestTime);
}

async function mapLimit(inputs, limit, iterateeFn, callback) {
    const result = [];
    let idx = 0;

    const handleExecution = async () => {
        if (idx < inputs.length) {
            const curr = inputs.slice(idx, idx + limit);
            idx += limit;

            const promises = curr.map(item => new Promise(resolve => {
                iterateeFn(item, res => {
                    result.push(res);
                    resolve();
                });
            }));

            await Promise.all(promises);
            await handleExecution(); // Recursively process the next batch
        }
    };

    await handleExecution(); // Start the process
    callback(result);
}

