function mapLimit (arr, workers, itretor, cb) {
	const output = [];
	const fns = Array(arr.length).fill(itretor).entries();
  const it = Array(workers).fill(fns);
  async function doWork(worker) {
  	for (let [ind, val] of worker) {
    	const result = await val(arr[ind], getNameById);
      output[ind] = result;
    }
  }
  Promise.all(it.map(doWork)).then(() => cb(output));
}
